INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Excel avancé niveau 1 & 2', 'Formation avancée sur Excel niveau 1 et 2 pour maîtriser les fonctions, outils et automatisations.', 5, 150000.00, 'entreprise', '2026-09-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Maîtriser les fonctions avancées d’Excel\n• Utiliser les tableaux croisés dynamiques et graphiques\n• Automatiser les tâches avec les macros\n• Optimiser l’analyse et la présentation des données\n• Gagner en efficacité et productivité\n\n--- OBJECTIFS DÉTAILLÉS ---\nFormer les participants à l’utilisation avancée d’Excel, leur apprendre à analyser et présenter les données efficacement, automatiser les tâches et optimiser la productivité.\n\n--- PRÉREQUIS ---\nMaîtrise des bases d’Excel (niveau débutant/intermédiaire).\n\n--- CONTENU ---\nModule 1 : Fonctions avancées d’Excel\nModule 2 : Tableaux croisés dynamiques\nModule 3 : Graphiques et visualisation des données\nModule 4 : Automatisation avec macros\nModule 5 : Gestion et analyse de bases de données\nModule 6 : Atelier pratique – Projet Excel avancé\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nAnalystes, comptables, gestionnaires, étudiants et toute personne utilisant Excel de manière professionnelle.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, ateliers pratiques, exercices guidés et mini-projets.\n\n--- SUPPORTS ---\nMicrosoft Excel, modèles de fichiers, supports PDF, slides et tutoriels pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
